INSERT INTO news (title, summary, content, channel, source, image_url, view_count, comment_count, is_breaking, publish_time, created_at, updated_at, source_url) 
VALUES 
('2026年大数据发展趋势分析', '2026年大数据技术发展趋势：实时分析、AI融合、边缘计算成为热点', '<h2>2026年大数据发展趋势</h2><p>今年大数据技术发展迅速，实时分析、AI融合、边缘计算成为热点，越来越多企业开始利用大数据提升业务效率。</p>', '大数据', '行业分析', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&h=400&fit=crop', 1234, 45, 0, 1778764800000, NOW(), NOW(), 'https://example.com/bigdata-trends-2026'),
('实时流数据处理技术综述', 'Flink、Kafka、Spark Streaming等实时流处理技术对比分析', '<h2>实时流数据处理技术</h2><p>流数据处理是大数据领域的重要技术，Flink、Kafka、Spark Streaming各有特色，企业需根据场景选择合适的方案。</p>', '大数据', '技术博客', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&h=400&fit=crop', 876, 32, 0, 1778678400000, NOW(), NOW(), 'https://example.com/stream-processing'),
('数据湖与数据仓库架构对比', '现代数据分析架构：数据湖、数据仓库、湖仓一体的优缺点分析', '<h2>数据湖与数据仓库</h2><p>现代数据分析架构有多种选择：数据湖、数据仓库、湖仓一体，每种都有自己的优缺点，需要根据业务需求选择。</p>', '大数据', '技术文章', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&h=400&fit=crop', 654, 28, 0, 1778592000000, NOW(), NOW(), 'https://example.com/data-lake-house'),
('数据安全与隐私保护实践', 'GDPR、数据加密、访问控制等数据安全实践指南', '<h2>数据安全与隐私保护</h2><p>在大数据时代，数据安全和隐私保护越来越重要，GDPR、数据加密、访问控制是必要的措施。</p>', '大数据', '安全指南', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&h=400&fit=crop', 543, 21, 0, 1778505600000, NOW(), NOW(), 'https://example.com/data-security');
INSERT INTO news (title, summary, content, channel, source, image_url, view_count, comment_count, is_breaking, publish_time, created_at, updated_at, source_url) 
VALUES 
('云原生技术2026年发展', 'Kubernetes、容器化、微服务架构是云原生的关键技术', '<h2>云原生技术发展</h2><p>2026年，云原生技术发展迅速，Kubernetes、容器化、微服务架构成为企业标准选择。</p>', '云计算', '云原生资讯', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=400&fit=crop', 987, 38, 0, 1778764800000, NOW(), NOW(), 'https://example.com/cloud-native-2026'),
('多云架构最佳实践', '如何设计和实施高效的多云策略，平衡成本和性能', '<h2>多云架构最佳实践</h2><p>多云架构已成为企业的主流选择，本文介绍如何设计和实施高效的多云策略，平衡成本和性能。</p>', '云计算', '云架构指南', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=400&fit=crop', 765, 29, 0, 1778678400000, NOW(), NOW(), 'https://example.com/multi-cloud'),
('Serverless架构深度解析', '无服务器计算的优势、适用场景和技术选型', '<h2>Serverless架构解析</h2><p>Serverless架构为开发者提供了更简洁的部署方式，本文深入解析无服务器计算的优势、适用场景和技术选型。</p>', '云计算', '技术解析', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=400&fit=crop', 654, 26, 0, 1778592000000, NOW(), NOW(), 'https://example.com/serverless'),
('云成本优化策略', '如何合理规划云资源，节约成本同时保证业务需求', '<h2>云成本优化策略</h2><p>云成本优化是每个企业都面临的挑战，本文介绍如何合理规划云资源，节约成本同时保证业务需求。</p>', '云计算', '成本管理', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=400&fit=crop', 543, 22, 0, 1778505600000, NOW(), NOW(), 'https://example.com/cloud-cost');
INSERT INTO news (title, summary, content, channel, source, image_url, view_count, comment_count, is_breaking, publish_time, created_at, updated_at, source_url) 
VALUES 
('2026年创业成功案例分析', '深入分析今年最成功的创业公司的发展模式和经验', '<h2>2026年创业成功案例</h2><p>2026年有很多成功的创业公司，本文分析了他们的发展模式和经验，给创业者带来启发。</p>', '创业', '创业媒体', 'https://images.unsplash.com/photo-1559136555-9303baea8ebd?w=800&h=400&fit=crop', 1123, 48, 0, 1778764800000, NOW(), NOW(), 'https://example.com/startup-success-2026'),
('AI时代的创业机遇', '人工智能技术发展带来的新创业方向和商业模式', '<h2>AI时代的创业机遇</h2><p>人工智能技术带来了巨大的创业机遇，本文介绍了多个可能的创业方向和新的商业模式。</p>', '创业', 'AI创业', 'https://images.unsplash.com/photo-1559136555-9303baea8ebd?w=800&h=400&fit=crop', 876, 35, 0, 1778678400000, NOW(), NOW(), 'https://example.com/ai-opportunities'),
('融资攻略：如何获得种子轮投资', '创业者如何准备、定位和获得第一轮种子投资', '<h2>融资攻略</h2><p>获得种子轮投资是创业的关键一步，本文介绍如何准备、定位和获得第一轮种子投资。</p>', '创业', '融资指南', 'https://images.unsplash.com/photo-1559136555-9303baea8ebd?w=800&h=400&fit=crop', 765, 30, 0, 1778592000000, NOW(), NOW(), 'https://example.com/seed-funding');
INSERT INTO news (title, summary, content, channel, source, image_url, view_count, comment_count, is_breaking, publish_time, created_at, updated_at, source_url) 
VALUES 
('新型AI芯片发布，性能提升5倍', '新一代人工智能处理芯片发布，计算能力大幅提升', '<h2>新型AI芯片发布</h2><p>科技巨头发布新一代人工智能处理芯片，性能相比上一代产品提升了5倍，将加速AI应用的发展。</p>', '硬件', '芯片资讯', 'https://images.unsplash.com/photo-1518770660439-4636190af475?w=800&h=400&fit=crop', 1345, 56, 0, 1778764800000, NOW(), NOW(), 'https://example.com/new-ai-chip'),
('2026年消费电子新品汇总', '今年最受期待的消费电子产品一览', '<h2>2026消费电子新品</h2><p>今年有很多令人期待的消费电子产品，从智能手机到智能家居，本文为您盘点一下。</p>', '硬件', '消费电子', 'https://images.unsplash.com/photo-1518770660439-4636190af475?w=800&h=400&fit=crop', 987, 40, 0, 1778678400000, NOW(), NOW(), 'https://example.com/consumer-electronics-2026'),
('边缘计算设备发展迅速', '边缘计算硬件设备市场快速增长，应用场景越来越丰富', '<h2>边缘计算设备发展</h2><p>边缘计算硬件设备市场快速增长，应用场景越来越丰富，从工业物联网到智能家居都有应用。</p>', '硬件', '硬件观察', 'https://images.unsplash.com/photo-1518770660439-4636190af475?w=800&h=400&fit=crop', 654, 27, 0, 1778592000000, NOW(), NOW(), 'https://example.com/edge-devices');
INSERT INTO news (title, summary, content, channel, source, image_url, view_count, comment_count, is_breaking, publish_time, created_at, updated_at, source_url) 
VALUES 
('新一代开发工具提升效率50%', '2026年最新开发工具让开发效率大幅提升', '<h2>新一代开发工具</h2><p>2026年最新的开发工具让编程效率提升了50%，AI辅助编程成为标配。</p>', '软件', '开发工具', 'https://images.unsplash.com/photo-1461749280684-dccba630e2f6?w=800&h=400&fit=crop', 1098, 43, 0, 1778764800000, NOW(), NOW(), 'https://example.com/new-dev-tools'),
('低代码平台2026年发展趋势', '低代码/无代码平台如何改变软件开发方式', '<h2>低代码平台趋势</h2><p>低代码/无代码平台继续快速发展，正在改变软件开发方式，让更多人可以参与开发。</p>', '软件', '低代码', 'https://images.unsplash.com/photo-1461749280684-dccba630e2f6?w=800&h=400&fit=crop', 765, 32, 0, 1778678400000, NOW(), NOW(), 'https://example.com/low-code-2026'),
('开源软件最新动态', '开源社区的最新项目和发展趋势', '<h2>开源软件动态</h2><p>开源软件社区继续蓬勃发展，有很多令人激动的新项目，本文为您带来最新动态。</p>', '软件', '开源资讯', 'https://images.unsplash.com/photo-1461749280684-dccba630e2f6?w=800&h=400&fit=crop', 654, 26, 0, 1778592000000, NOW(), NOW(), 'https://example.com/open-source-2026');
